import{_ as a,c as e,o as r,ak as o}from"./chunks/framework.uXmbDaEn.js";const m=JSON.parse('{"title":"明明可以避免的，為什麼還是讓它發生了？","description":"有些事看起來像是突然發生的，其實早就有跡可循。從感情的冷淡、親子的疏離，到身體的警訊，我們是不是早就知道結果，卻還是選擇忽略？ 標籤: 關係 標籤: 生活觀察 標籤: 心情 標籤: 自省 標籤: 感情 分類: 隨筆","frontmatter":{"date":"2025-05-26T08:46:54.000Z","author":"聖小熊","title":"明明可以避免的，為什麼還是讓它發生了？","listDate":"2025-05-26T00:00:00.000Z","description":"有些事看起來像是突然發生的，其實早就有跡可循。從感情的冷淡、親子的疏離，到身體的警訊，我們是不是早就知道結果，卻還是選擇忽略？","tag":["關係","生活觀察","心情","自省","感情"],"category":["隨筆"]},"headers":[],"relativePath":"blog/2025-05-26.md","filePath":"blog/2025-05-26.md","lastUpdated":1748539623000}'),p={name:"blog/2025-05-26.md"};function s(_,t,n,i,l,d){return r(),e("div",null,t[0]||(t[0]=[o('<p>有時候真的會覺得，很多事情根本不是什麼「突然發生」的。<br> 你長期抽菸，得肺癌的機率就超高；你從來不運動，年紀一大身體一定出狀況；你現在對小孩很差，他們長大後對你冷淡一點，其實也不太意外。</p><p>這些東西看起來像意外，其實根本都早就寫在前面了。只是大家都不想去想、不想面對而已。</p><h2 id="感情的事也是一樣。" tabindex="-1">感情的事也是一樣。 <a class="header-anchor" href="#感情的事也是一樣。" aria-label="Permalink to “感情的事也是一樣。”">​</a></h2><p>一開始熱得要命，然後慢慢變冷，開始不講話、開始不懂彼此，說真的，那些改變都是一點一滴累積出來的。只是我們每次都覺得「沒事啦」、「應該會好吧」，但那些「沒關係」，最後就變成一句「算了」。</p><p>等到結局真的發生了，才會回頭發現「欸？其實那時候就已經有跡象了欸！只是我們沒理它」</p><p>然後你就會開始想：<br> 如果早就知道會變這樣，<br> 那當初為什麼還是讓它變成這樣？</p>',6)]))}const f=a(p,[["render",s]]);export{m as __pageData,f as default};
